class BiometricAuth {
  static final LocalAuthentication _auth = LocalAuthentication();

  Future<bool> authenticate() async {
    try {
      final bool isAvailable = await _auth.isPlatformSupported();
      if (!isAvailable) {
        return false;
      }

      final List<BiometricType> availableBiometrics =
          await _auth.getAvailableBiometrics();
      if (availableBiometrics.isEmpty) {
        return false;
      }

      final bool authenticated = await _auth.authenticate(
        localizedReason: 'Please authenticate',
        useLegacyAuth: true,
        onResult: (result) {
          if (result == AuthenticationStatus.success) {
            saveAuthenticationStatus(true);
          }
        },
      );

      return authenticated;
    } catch (e) {
      print('Error: $e');
      return false;
    }
  }

  Future<void> saveAuthenticationStatus(bool status) async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    prefs.setBool('isAuthenticated', status);
  }

  bool getIsAuthenticated() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    return prefs.getBool('isAuthenticated') ?? false;
  }
}

